parameters.text:
=Please analyze the following email and output the JSON as instructed. 

--- EMAIL START ---
Subject: {{ $json.subject }}
Sender: {{ $json.from_address }}
To: {{ $json.to_address }}
CC: {{ $json.cc_addresses }}
Body: {{ $json.llm_body }}
--- EMAIL END ---

parameters.jsCode:
const EXCLUDED_EMAILS = [
  "placements.sv@scalevirtually.com",
  "ace@scalevirtually.com",
  "ck@scalevirtually.com",
  "bam@scalevirtually.com",
  "karlo@scalevirtually.com"
];

const results = [];
for (const item of $input.all()) {
  const email = item.json;

  const toEmails = email.to?.value?.map(p => p.address.toLowerCase()) || [];
  const ccEmails = email.cc?.value?.map(p => p.address.toLowerCase()) || [];

  // Skip if the primary To recipient is an excluded internal email
  const primaryTo = toEmails[0] || "";
  if (EXCLUDED_EMAILS.includes(primaryTo)) continue;

  // Also skip if ALL To recipients are internal
  const hasExternalTo = toEmails.some(addr => !EXCLUDED_EMAILS.includes(addr));
  if (!hasExternalTo) continue;

  const rawBody = email.text || "";
  let llmBody = rawBody.split(/thanks and regards/i)[0].trim();
  const sender = email.from?.value?.[0]?.address || "";
  const recipient = toEmails[0] || "";
  const allParticipants = [...new Set([sender, ...toEmails, ...ccEmails])].filter(e => e !== "");
  const formulaParts = allParticipants.map(emailAddr => {
    const lowerEmail = emailAddr.toLowerCase();
    return `FIND('${lowerEmail}', LOWER(ARRAYJOIN({Email (from Client)}, ' '))), FIND('${lowerEmail}', LOWER(ARRAYJOIN({POC Primary email}, ' ')))`;
  });
  const airtableFormula = `OR(${formulaParts.join(", ")})`;
  const priorityLabels = (email.labelIds || []).filter(l => !["UNREAD", "INBOX", "IMPORTANT"].includes(l));
  results.push({
    json: {
      from_address: sender,
      to_address: recipient,
      to_addresses: toEmails.join(", "),
      cc_addresses: ccEmails.join(", "),
      airtableFormula: airtableFormula,
      full_body: rawBody,
      llm_body: llmBody,
      subject: email.subject,
      date: email.date,
      prompt_context_string: `
CONTEXT:
- Subject: ${email.subject}
- From: ${sender}
- To: ${toEmails.join(", ")}
- CC: ${ccEmails.join(", ")}
- Date: ${email.date}
MESSAGE:
${llmBody}
      `.trim()
    }
  });
}
return results;

// Get the output string from the AI Agent
const rawOutput = $json.output;

// 1. Remove Markdown code blocks using Regex
// This strips ```json, ```, and any leading/trailing whitespace
const cleanString = rawOutput.replace(/```json|```/g, "").trim();

try {
  // 2. Parse the string into a JavaScript Object
  const parsedData = JSON.parse(cleanString);

  // 3. Return the parsed data as the new node output
  return {
    category: parsedData.category,
    insights: parsedData.insights,
    priority: parsedData.priority
  };
} catch (error) {
  // Fallback in case the AI outputs something that isn't valid JSON
  return {
    error: "Failed to parse JSON",
    raw: rawOutput
  };
}

const items = $input.all();

// ── 1. SENDER / RECIPIENT EXCLUSIONS ──
const excludedSenders = [
  "placements.sv",
  "ck",
  "ace",
  "bam",
  "karlo"
];

const excludedRecipients = [
  "placements.sv@scalevirtually.com"
];

// ── 2. TRIVIAL BODY PATTERNS (internal senders only) ──
const trivialPatterns = /^(received|noted|thanks|thank you|got it|ok|okay|acknowledged|confirmed|copy|noted with thanks|will do|seen|ack)\.?!?$/i;

// ── 3. TEST / NOISE SUBJECT PATTERNS ──
const noiseSubjects = /\b(test email|just a random|testing|ignore this|test message)\b/i;

const filtered = items.filter(item => {
  const email = item.json;
  const fromText  = (email.from?.text || email.from || "").toLowerCase();
  const toText    = (email.to?.text   || email.to   || "").toLowerCase();
  const subject   = (email.subject    || "").toLowerCase();
  const rawBody   = email.text        || "";

  // ── RULE 1: Block excluded senders ──
  if (excludedSenders.some(s => fromText.includes(s))) {
    return false;
  }

  // ── RULE 2: Block excluded recipients ──
  if (excludedRecipients.some(r => toText.includes(r))) {
    return false;
  }

  // ── RULE 3: Block noise subjects ──
  if (noiseSubjects.test(subject)) {
    return false;
  }

  // ── RULE 4: Block trivial-body emails (INTERNAL SENDERS ONLY) ──
  const senderAddress = (
    email.from?.value?.[0]?.address ||
    email.from?.text ||
    email.from ||
    ""
  ).toLowerCase();

  const isInternal = senderAddress.includes("@scalevirtually.com") ||
                     senderAddress.includes("@scalevirtually.ph");

  if (isInternal) {
    const cleanBody = stripQuotedAndSignature(rawBody);
    if (cleanBody.length < 20 || trivialPatterns.test(cleanBody)) {
      return false;
    }
  }

  return true;
});

return filtered;

// ── HELPER: Extract only the sender's actual message ──
function stripQuotedAndSignature(text) {
  let clean = text;

  // Remove quoted replies ("On [date], [name] wrote:")
  clean = clean.split(/\r?\nOn .+wrote:\s*$/m)[0];

  // Remove signature blocks
  clean = clean.split(/\r?\n\s*(thanks and regards|best regards|regards|best|cheers|sincerely|thanks|thank you),?\s*\r?\n/i)[0];

  // Remove image placeholders, phone numbers, URLs, email addresses
  clean = clean
    .replace(/\[image:.*?\]/g, "")
    .replace(/\(?\d{3}\)?[\s.-]?\d{3}[\s.-]?\d{4}/g, "")
    .replace(/https?:\/\/\S+/g, "")
    .replace(/\S+@\S+\.\S+/g, "")
    .replace(/\n{2,}/g, "\n")
    .trim();

  return clean;
}

